

/* js/router.js */

/*==================================================
                GOCES ROUTER v3.0
==================================================*/

let currentPage = "home";
let pageHistory = [];

/*==================================================
                CACHE
==================================================*/

const pages = {};
const navs = {};

/*==================================================
                INITIALIZE
==================================================*/

document.addEventListener("DOMContentLoaded", initRouter);

function initRouter() {

    document.querySelectorAll(".goces-page").forEach(page => {

        pages[page.id.replace("page-", "")] = page;

    });

    document.querySelectorAll(".goces-nav-item").forEach(nav => {

        navs[nav.dataset.page] = nav;

    });

    history.replaceState(
        {
            page: currentPage
        },
        "",
        "#" + currentPage
    );

}

/*==================================================
                UPDATE PAGE
==================================================*/

function updatePage(page) {

    if (!pages[page]) {

        console.warn("Page tidak ditemukan :", page);

        return false;

    }

    Object.values(pages).forEach(item => {

        item.classList.remove("goces-active");

    });

    pages[page].classList.add("goces-active");

    Object.values(navs).forEach(item => {

        item.classList.remove("goces-active");

    });

    if (navs[page]) {

        navs[page].classList.add("goces-active");

    }

    window.scrollTo(0, 0);

    currentPage = page;

    return true;

}

/*==================================================
                SHOW PAGE
==================================================*/

function showPage(page) {

    if (!page) return;

    if (page === currentPage) return;

    if (!pages[page]) return;

    const last = pageHistory[pageHistory.length - 1];

    if (last !== currentPage) {

        pageHistory.push(currentPage);

    }

    history.pushState(
        {
            page: page
        },
        "",
        "#" + page
    );

    updatePage(page);

}

/*==================================================
                REPLACE PAGE
==================================================*/

function replacePage(page) {

    if (!page) return;

    if (!pages[page]) return;

    history.replaceState(
        {
            page: page
        },
        "",
        "#" + page
    );

    updatePage(page);

}

/*==================================================
                GO BACK
==================================================*/

function goBack() {

    if (pageHistory.length > 0) {

        history.back();

        return;

    }

    window.location.href = "action://act/back";

}

/*==================================================
            ANDROID / BROWSER BACK
==================================================*/

window.addEventListener("popstate", function () {

    if (pageHistory.length === 0) {

        currentPage = "home";

        return;

    }

    const previous = pageHistory.pop();

    updatePage(previous);

});

/*==================================================
                RESET HISTORY
==================================================*/

function resetHistory() {

    pageHistory = [];

}

/*==================================================
                GET CURRENT PAGE
==================================================*/

function getCurrentPage() {

    return currentPage;

}

/*==================================================
                GET PREVIOUS PAGE
==================================================*/

function getPreviousPage() {

    if (pageHistory.length === 0) {

        return null;

    }

    return pageHistory[pageHistory.length - 1];

}

/*==================================================
                CAN GO BACK
==================================================*/

function canGoBack() {

    return pageHistory.length > 0;

}

/* js/navigation.js */

/*==================================================
            GOCES NAVIGATION
==================================================*/

document.addEventListener("DOMContentLoaded", () => {

    document
        .querySelectorAll(".goces-nav-item, .goces-qris-btn")
        .forEach(button => {

            button.addEventListener("click", function () {

                const page = this.dataset.page;

                if (!page) return;

                showPage(page);

            });

        });

});

/* js/feedback.js */

/*==================================================
        GOCES FEEDBACK ENGINE v3.0 FINAL
==================================================*/

const GocesFeedback = (() => {

    /*==================================
                CONFIG
    ==================================*/

    const CONFIG = {

        vibration: true,

        vibrationTime: 10,

        sound: true,

        volume: 0.35,

        soundFile: "https://goces-app.vercel.app/assets/audio/click.wav",

        animationDuration: 120

    };

    /*==================================
                AUDIO
    ==================================*/

    let audio = null;

    function initSound() {

        if (!CONFIG.sound) return;

        if (audio) return;

        audio = new Audio(CONFIG.soundFile);

        audio.preload = "auto";

        audio.volume = CONFIG.volume;

        audio.load();

    }

    /*==================================
            HAPTIC FEEDBACK
    ==================================*/

    function vibrate() {

        if (!CONFIG.vibration) return;

        if (!navigator.vibrate) return;

        navigator.vibrate(CONFIG.vibrationTime);

    }

    /*==================================
                SOUND
    ==================================*/

    function playSound() {

        if (!audio) return;

        try {

            audio.pause();

            audio.currentTime = 0;

            audio.play().catch(() => { });

        } catch (e) { }

    }

    /*==================================
            SCALE EFFECT
    ==================================*/

    function animate(element) {

        if (!element) return;

        if (element.animate) {

            element.getAnimations().forEach(anim => anim.cancel());

            element.animate(

                [

                    {
                        transform: "scale(1)"
                    },

                    {
                        transform: "scale(.95)"
                    },

                    {
                        transform: "scale(1)"
                    }

                ],

                {

                    duration: CONFIG.animationDuration,

                    easing: "ease-out"

                }

            );

        }

    }

    /*==================================
                PLAY
    ==================================*/

    function play(element = null) {

        vibrate();

        playSound();

        animate(element);

    }

    /*==================================
            AUTO ENABLE
    ==================================*/

    function enableAuto() {

        initSound();

        document.addEventListener(

            "pointerdown",

            function (e) {

                const target = e.target.closest(

                    "button,a,[data-feedback],.goces-click"

                );

                if (!target) return;

                play(target);

            },

            { passive: true }

        );

        document.addEventListener("visibilitychange", function () {

            if (!document.hidden && audio) {

                audio.load();

            }

        });

    }

    /*==================================
                API
    ==================================*/

    return {

        enableAuto,

        play

    };

})();

/* js/app.js */

document.addEventListener("DOMContentLoaded", function () {

  replacePage("home");

  GocesFeedback.enableAuto();

});

/* js/aktivitas/aktivitas.js */

document.addEventListener('DOMContentLoaded', () => {
    initTabSystem();
    initNativeRippleEffects();
});

/**
 * Premium iOS Tab Interface Switching Architecture
 */
function initTabSystem() {
    const tabButtons = document.querySelectorAll('.tab-pill');
    const tabContents = document.querySelectorAll('.tab-content');

    // Trigger visual entry initialization on active view
    const initialActiveContent = document.querySelector('.tab-content.active');
    if (initialActiveContent) {
        setTimeout(() => {
            initialActiveContent.classList.add('show');
        }, 50);
    }

    tabButtons.forEach(button => {
        button.addEventListener('click', () => {
            const targetTab = button.getAttribute('data-tab');

            // Prevent process execution if tab selected is already active
            if (button.classList.contains('active')) return;

            // Step 1: Remove active states on pills UI context
            tabButtons.forEach(btn => btn.classList.remove('active'));
            button.classList.add('active');

            // Step 2: Handle Content Fade out transitional sequence
            tabContents.forEach(content => {
                if (content.classList.contains('active')) {
                    content.classList.remove('show');

                    // Delay layout swap after animation finishes (250ms)
                    setTimeout(() => {
                        content.classList.remove('active');

                        // Step 3: Trigger entrance on target layout framework
                        const nextContent = document.querySelector(`[data-content="${targetTab}"]`);
                        if (nextContent) {
                            nextContent.classList.add('active');
                            // Small trick to ensure display property registers before transition
                            setTimeout(() => {
                                nextContent.classList.add('show');
                            }, 20);
                        }
                    }, 250);
                }
            });
        });
    });
}

/**
 * Creates lightweight native physical UI response (Ripple logic)
 */
function initNativeRippleEffects() {
    const buttons = document.querySelectorAll('.icon-btn');

    buttons.forEach(button => {
        button.addEventListener('click', function (e) {
            // Clear existing elements if user clicks consecutively rapidly
            const existingRipple = this.querySelector('.ripple');
            if (existingRipple) {
                existingRipple.remove();
            }

            const ripple = document.createElement('span');
            ripple.classList.add('ripple');

            const rect = this.getBoundingClientRect();
            const size = Math.max(rect.width, rect.height);

            ripple.style.width = ripple.style.height = `${size}px`;

            const x = e.clientX - rect.left - (size / 2);
            const y = e.clientY - rect.top - (size / 2);

            ripple.style.left = `${x}px`;
            ripple.style.top = `${y}px`;

            this.appendChild(ripple);

            // Housekeeping cleanup memory leaks prevention
            ripple.addEventListener('animationend', () => {
                ripple.remove();
            });
        });
    });
}

